import { readStoredAdminApiKey } from "@/utils/adminKeyAuth";
import { getProfile } from "@/utils/branding-shared";

export function getAnalyticsBrokerId() {
  const profile = getProfile();
  const storedKey = readStoredAdminApiKey({ skipWalletCheck: true });
  if (profile?.role === "ambassador") return "ambassador";
  return (
    profile?.brokerId ||
    storedKey?.brokerId ||
    (typeof window !== "undefined"
      ? window.localStorage.getItem("current_user_broker_id") || undefined
      : undefined)
  );
}
