import { orderlyApi } from "@/utils/api";
import { getOrderlyEnvConfig } from "@/utils/environment";

export type PublicInfoTopAddressesSort =
  | "notional"
  | "volume_24h"
  | "volume_7d"
  | "volume_30d"
  | "pnl_24h"
  | "pnl_7d"
  | "pnl_30d"
  | "trade_count_24h";

type PublicInfoQueryBody =
  | {
      type: "accounts";
      address?: string;
      broker_id?: string;
    }
  | {
      type: "topAddresses";
      symbol?: string;
      sort_by?: PublicInfoTopAddressesSort;
      min_notional?: string | number;
      limit?: number;
      cursor?: string;
    };

export interface PublicInfoEnvelope<T> {
  success: boolean;
  data?: T;
  code?: string;
  message?: string;
  ts?: number;
}

export interface PublicInfoAccountSummary {
  address?: string;
  broker_id?: string;
  account_id?: string;
  account_type?: "main" | "sub" | "sp" | string;
  account_value?: string | null;
}

export interface PublicInfoAccountsData {
  address?: string;
  accounts?: PublicInfoAccountSummary[];
}

export async function publicInfoQuery<T>(body: PublicInfoQueryBody) {
  const payload = await orderlyApi<PublicInfoEnvelope<T>>({
    endpoint: "/v1/public/query",
    method: "POST",
    body,
    token: null,
    baseUrl: getOrderlyEnvConfig().apiBaseUrl,
  });

  if (payload.success === false) {
    throw new Error(
      payload.message || payload.code || "Public Info API request failed."
    );
  }

  return payload;
}
