function appendEndpointQuery(
  endpoint: string,
  params: Record<string, number | string | undefined>
) {
  const [path, queryString = ""] = endpoint.split("?");
  const searchParams = new URLSearchParams(queryString);
  Object.entries(params).forEach(([key, value]) => {
    if (value === undefined || value === "") return;
    searchParams.set(key, String(value));
  });
  const nextQueryString = searchParams.toString();
  return nextQueryString ? `${path}?${nextQueryString}` : path;
}

function appendUserQuery(endpoint: string, user: UserRow) {
  if (user.account_id)
    return appendEndpointQuery(endpoint, { user_account: user.account_id });
  if (user.address)
    return appendEndpointQuery(endpoint, { user_address: user.address });
  return endpoint;
}

function buildUserDetailEndpoint(
  item: (typeof USER_DETAIL_ENDPOINTS)[number],
  user: UserRow,
  page: number
) {
  const endpoint = item.paginated
    ? appendEndpointQuery(item.endpoint, {
        page,
        size: USER_DETAIL_PAGE_SIZE,
      })
    : item.endpoint;
  return appendUserQuery(endpoint, user);
}

function getUserDetailPath(user: UserRow) {
  if (user.address) {
    const params = new URLSearchParams();
    if (user.account_id) params.set("account_id", user.account_id);
    if (user.account_type) params.set("account_type", user.account_type);
    const queryString = params.toString();
    return `/data-analytics/users/address/${encodeURIComponent(user.address)}${queryString ? `?${queryString}` : ""}`;
  }
  return getAccountDetailPath(user.account_id || "");
}

function getAccountDetailPath(accountId: string) {
  return `/data-analytics/users/account/${encodeURIComponent(accountId)}`;
}

function getUserFromRoute(
  mode?: string,
  value?: string,
  accountId?: string | null,
  accountType?: string | null
): UserRow | null {
  if (!value) return null;
  const decoded = decodeURIComponent(value);
  if (mode === "account") return { account_id: decoded };
  if (mode === "address")
    return {
      address: decoded,
      account_id: accountId || undefined,
      account_type: accountType || undefined,
    };
  return null;
}

function formatShort(value?: string, start = 8, end = 6) {
  if (!value) return "-";
  if (value.length <= start + end + 3) return value;
  return `${value.slice(0, start)}...${value.slice(-end)}`;
}

function buildClientInfoEndpoint(mode: QueryMode, value: string) {
  const params = new URLSearchParams();
  if (value.trim())
    params.set(
      mode === "address" ? "user_address" : "user_account",
      value.trim()
    );
  const queryString = params.toString();
  return queryString
    ? `/v1/admin/client/info?${queryString}`
    : "/v1/admin/client/info";
}

function clientInfoToUserRows(
  data: unknown,
  fallbackMode: QueryMode,
  fallbackValue: string
): UserRow[] {
  if (!data || typeof data !== "object") return [];
  const payload = data as { rows?: UserRow[] } & UserRow;
  const rows = Array.isArray(payload.rows)
    ? payload.rows
    : Object.keys(payload).length
      ? [payload]
      : [];
  return rows.map(row => ({
    ...row,
    address:
      row.address ||
      (fallbackMode === "address" ? fallbackValue.trim() : undefined),
    account_id:
      row.account_id ||
      (fallbackMode === "account" ? fallbackValue.trim() : undefined),
  }));
}

function getAccountTypeRank(accountType?: string) {
  const normalized = accountType?.toLowerCase();
  if (normalized === "main") return 0;
  if (normalized === "sub") return 1;
  return 2;
}

function sortPublicAccounts(accounts: PublicInfoAccountSummary[]) {
  return [...accounts].sort((a, b) => {
    const typeDiff =
      getAccountTypeRank(a.account_type) - getAccountTypeRank(b.account_type);
    if (typeDiff !== 0) return typeDiff;
    return (a.account_id || "").localeCompare(b.account_id || "");
  });
}

async function fetchAdminClientInfo(mode: QueryMode, value: string) {
  const response = await signedAdminRequest<RowsResponse<UserRow>>({
    endpoint: buildClientInfoEndpoint(mode, value),
  });
  if (response.success === false)
    throw new Error(response.message || "Failed to load user profile.");
  return clientInfoToUserRows(response.data, mode, value);
}

async function searchAddressUsers(address: string, brokerId: string) {
  const response = await publicInfoQuery<PublicInfoAccountsData>({
    type: "accounts",
    address,
    broker_id: brokerId,
  });
  const publicAccounts = sortPublicAccounts(response.data?.accounts || []);

  return publicAccounts.map(account => ({
    address: response.data?.address || address,
    broker_id: account.broker_id || brokerId,
    account_id: account.account_id,
    account_type: account.account_type,
    account_value: account.account_value,
  }));
}

async function searchUsers(mode: QueryMode, value: string, brokerId?: string) {
  const trimmed = value.trim();
  if (mode === "address") {
    if (!brokerId)
      throw new Error("Broker ID is required before searching by address.");
    return searchAddressUsers(trimmed, brokerId);
  }

  return fetchAdminClientInfo("account", trimmed);
}

function rowsFromPayload(payload: unknown): unknown[] {
  if (responseErrorMessage(payload)) return [];
  const data = objectFromPayload(payload);
  if (!data) return [];
  if (Array.isArray(data.rows)) return data.rows;
  if (Array.isArray(data.holding)) return data.holding;
  const rowKeys = Object.keys(data).filter(
    key => !["meta", "timestamp", "success", "message"].includes(key)
  );
  if (!rowKeys.length) return [];
  return [data];
}

function userFromInfoPayload(payload: unknown): UserRow | null {
  const rows = rowsFromPayload(payload);
  const first = rows[0];
  return first && typeof first === "object" ? (first as UserRow) : null;
}

function displayValue(value: unknown) {
  if (value === null || value === undefined || value === "") return "-";
  if (typeof value === "object") return JSON.stringify(value);
  return String(value);
}

