function isTimestampColumn(column: string) {
  return /(^timestamp$|_timestamp$|^time$|_time$|_at$)/i.test(column);
}

function isSideColumn(column: string) {
  return /(^side$|_side$)/i.test(column);
}

function isNumericDisplayColumn(column: string) {
  return !/(^|_)(id|address|hash|tag|type|side|status|symbol|asset|currency|token|time|timestamp|at)$/i.test(
    column
  );
}

function formatNumericDisplayValue(value: unknown) {
  if (value === null || value === undefined || value === "") return "-";
  const raw = String(value).trim();
  if (!/^-?\d+(?:\.\d+)?$/.test(raw)) return displayValue(value);
  const sign = raw.startsWith("-") ? "-" : "";
  const unsigned = sign ? raw.slice(1) : raw;
  const [integer, fraction] = unsigned.split(".");
  const integerWithSeparators = integer.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  return `${sign}${integerWithSeparators}${fraction ? `.${fraction}` : ""}`;
}

function renderDisplayValue(column: string, value: unknown) {
  if (isChainColumn(column)) return <ChainCell value={value} />;
  if (isTimestampColumn(column)) return formatTimestampValue(value);
  if (isNumericDisplayColumn(column)) return formatNumericDisplayValue(value);
  return displayValue(value);
}

function SideCell({ value }: { value: unknown }) {
  const label = displayValue(value);
  const normalized = label.toLowerCase();
  const className = normalized.includes("buy")
    ? "border-(--line-positive) bg-(--bg-positive-subtle) text-(--fg-positive)"
    : normalized.includes("sell")
      ? "border-(--line-negative) bg-(--bg-negative-subtle) text-(--fg-negative)"
      : "border-(--line-subtle) bg-(--bg-surface-primary) text-(--fg-secondary)";

  return (
    <span
      className={`inline-flex rounded-full border px-2 py-0.5 text-[10px] font-semibold uppercase tracking-[0.1em] ${className}`}
    >
      {label}
    </span>
  );
}

function displayAccountValue(value: unknown) {
  if (value === null || value === undefined || value === "") return "-";
  const raw = String(value).trim();
  const match = raw.match(/^(-?)(\d+)(?:\.(\d+))?$/);
  if (!match) return raw;
  const [, sign, whole, fraction = ""] = match;
  const formattedWhole = whole.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  const truncated = fraction.slice(0, 6).replace(/0+$/, "");
  return `${sign}${formattedWhole}${truncated ? `.${truncated}` : ""}`;
}

function displayAccountType(value?: string) {
  if (!value) return "-";
  const normalized = value.toLowerCase();
  if (normalized === "main") return "Main";
  if (normalized === "sub") return "Sub-account";
  return value;
}

function accountTypeBadgeClass(value?: string) {
  const normalized = value?.toLowerCase();
  if (normalized === "main") {
    return "border-(--line-brand) bg-[rgba(188,135,255,0.16)] text-(--fg-brand)";
  }
  if (normalized === "sub") {
    return "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)";
  }
  return "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-tertiary)";
}

function CopyButton({ value, label }: { value?: string; label: string }) {
  const [copied, setCopied] = useState(false);

  async function handleCopy(event: MouseEvent<HTMLButtonElement>) {
    event.preventDefault();
    event.stopPropagation();
    if (!value) return;
    await navigator.clipboard.writeText(value);
    setCopied(true);
    window.setTimeout(() => setCopied(false), 1200);
  }

  return (
    <button
      type="button"
      onClick={handleCopy}
      disabled={!value}
      aria-label={`Copy ${label}`}
      title={copied ? "Copied" : `Copy ${label}`}
      className={`inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-md transition-colors disabled:cursor-not-allowed disabled:opacity-40 ${copied ? "text-[#1DF6B5]" : "text-(--fg-tertiary) hover:bg-(--bg-hover) hover:text-(--fg-primary)"}`}
    >
      {copied ? (
        <Check className="h-3.5 w-3.5" />
      ) : (
        <Copy className="h-3.5 w-3.5" />
      )}
    </button>
  );
}

