  const [resultMode, setResultMode] = useState<QueryMode>("address");
  const [loadingUsers, setLoadingUsers] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    loadUsers();
  }, []);

  async function loadUsers() {
    const trimmed = query.trim();
    if (!trimmed) {
      setUsers([]);
      return;
    }
    const brokerId = mode === "address" ? getAnalyticsBrokerId() : undefined;
    if (mode === "address" && !brokerId) {
      setUsers([]);
      setError("Broker ID is required before searching user analytics.");
      return;
    }
    setError("");
    setLoadingUsers(true);
    try {
      const nextUsers = await searchUsers(mode, trimmed, brokerId);
      if (mode === "account") {
        if (!nextUsers.length) {
          setUsers([]);
          setError("No matching account found.");
          return;
        }
        setUsers([]);
        navigate(getAccountDetailPath(nextUsers[0].account_id || trimmed));
        return;
      }
      setResultMode(mode);
      setUsers(nextUsers);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load users.");
    } finally {
      setLoadingUsers(false);
    }
  }

